import sys
from collections import defaultdict
input = sys.stdin.readline

def solve():
    n, m = map(int, input().split())
    x = list(map(int, input().split()))
    s = []
    for _ in range(n):
        s.append(input().strip())

    sig_to_questions = defaultdict(list)
    for j in range(m):
        mask = 0
        for i in range(n):
            if s[i][j] == '1':
                mask |= (1 << i)
        sig_to_questions[mask].append(j)

    sig_counts = {mask: len(qs) for mask, qs in sig_to_questions.items()}
    sig_qs = {mask: list(qs) for mask, qs in sig_to_questions.items()}
    rem = dict(sig_counts)

    p = [0] * m
    r = [0] * n

    for v in range(m, 0, -1):
        best_gain = None
        best_mask = None

        for mask, cnt in rem.items():
            if cnt == 0:
                continue
            # gain of assigning v vs assigning 1 to this mask
            gain = 0
            for i in range(n):
                if mask & (1 << i):
                    gain += abs(x[i] - r[i] - v) - abs(x[i] - r[i] - 1)
            if best_gain is None or gain > best_gain:
                best_gain = gain
                best_mask = mask

        rem[best_mask] -= 1
        j = sig_qs[best_mask][rem[best_mask]]
        p[j] = v
        for i in range(n):
            if best_mask & (1 << i):
                r[i] += v

    # Fill remaining with 1s - but wait, each value is used exactly once
    # The loop assigns each value from m down to 1, so all are assigned
    print(*p)

t = int(input())
for _ in range(t):
    solve()

